// TestMergeParallelBasic tests basic merge scenarios
func TestMergeParallelBasic(t *testing.T) {
	tests := []struct {
		name         string
		origin       string
		ours         string
		theirs       string
		style        int
		wantConflict bool
	}{
		{
			name:         "conflict_default",
			origin:       "line1\nline2\n",
			ours:         "line1a\nline2\n",
			theirs:       "line1b\nline2\n",
			style:        STYLE_DEFAULT,
			wantConflict: true,
		},
		{
			name:         "conflict_diff3",
			origin:       "line1\nline2\n",
			ours:         "line1a\nline2\n",
			theirs:       "line1b\nline2\n",
			style:        STYLE_DIFF3,
			wantConflict: true,
		},
		{
			name:         "no_conflict_adjacent",
			origin:       "line1\nline2\n",
			ours:         "line1a\nline2\n",
			theirs:       "line1\nline2a\n",
			style:        STYLE_DEFAULT,
			wantConflict: false, // Adjacent (non-overlapping) changes should NOT conflict
		},
		{
			name:         "empty_texts",
			origin:       "",
			ours:         "",
			theirs:       "",
			style:        STYLE_DEFAULT,
			wantConflict: false,
		},
		{
			name:         "ours_empty",
			origin:       "line1\nline2\n",
			ours:         "",
			theirs:       "line1\nline2\n",
			style:        STYLE_DEFAULT,
			wantConflict: false,
		},
		{
			name:         "theirs_empty",
			origin:       "line1\nline2\n",
			ours:         "line1\nline2\n",
			theirs:       "",
			style:        STYLE_DEFAULT,
			wantConflict: false,
		},
		{
			name:         "same_change_both",
			origin:       "line1\nline2\n",
			ours:         "line1a\nline2\n",
			theirs:       "line1a\nline2\n",
			style:        STYLE_DEFAULT,
			wantConflict: false, // Same change should not conflict
		},
		{
			name:         "only_ours_changed",
			origin:       "line1\nline2\n",
			ours:         "line1a\nline2\n",
			theirs:       "line1\nline2\n",
			style:        STYLE_DEFAULT,
			wantConflict: false,
		},
		{
			name:         "only_theirs_changed",
			origin:       "line1\nline2\n",
			ours:         "line1\nline2\n",
			theirs:       "line1b\nline2\n",
			style:        STYLE_DEFAULT,
			wantConflict: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()
			opts := &MergeOptions{
				TextO: tt.origin,
				TextA: tt.ours,
				TextB: tt.theirs,
				Style: tt.style,
				A:     Histogram,
			}

			result, hasConflict, err := MergeParallel(ctx, opts)
			if err != nil {
				t.Fatalf("MergeParallel() error = %v", err)
			}

			if hasConflict != tt.wantConflict {
				t.Errorf("MergeParallel() hasConflict = %v, want %v", hasConflict, tt.wantConflict)
			}

			// Verify conflict markers are present when expected
			if tt.wantConflict && !strings.Contains(result, "<<<<<<<") {
				t.Errorf("MergeParallel() result should contain conflict markers when hasConflict=true")
			}

			if !tt.wantConflict && strings.Contains(result, "<<<<<<<") {
				t.Errorf("MergeParallel() result should not contain conflict markers when hasConflict=false")
			}
		})
	}
}

// ============================================================================
// Comparison Tests: MergeParallel vs Merge
// ============================================================================

// TestMergeParallelVsMerge compares MergeParallel with original Merge
func TestMergeParallelVsMerge(t *testing.T) {
	tests := []struct {
		name   string
		origin string
		ours   string
		theirs string
		style  int
	}{
		{
			name:   "simple_conflict",
			origin: "line1\nline2\n",
			ours:   "line1a\nline2\n",
			theirs: "line1b\nline2\n",
			style:  STYLE_DEFAULT,
		},
		// Note: "adjacent_conflict" test removed because Merge and MergeParallel
		// handle adjacent (non-overlapping) changes differently:
		// - Merge uses <= for overlap check (treats adjacent as conflict)
		// - MergeParallel uses < for overlap check (correct: adjacent is NOT conflict)
		{
			name:   "diff3_style",
			origin: "line1\nline2\n",
			ours:   "line1a\nline2\n",
			theirs: "line1b\nline2\n",
			style:  STYLE_DIFF3,
		},
		{
			name:   "no_trailing_newline_conflict",
			origin: "line1\nline2",
			ours:   "line1\nline2a",
			theirs: "line1\nline2b",
			style:  STYLE_DEFAULT,
		},
		{
			name:   "no_change_ours",
			origin: "line1\nline2\n",
			ours:   "line1\nline2\n",
			theirs: "line1b\nline2\n",
			style:  STYLE_DEFAULT,
		},
		{
			name:   "no_change_theirs",
			origin: "line1\nline2\n",
			ours:   "line1a\nline2\n",
			theirs: "line1\nline2\n",
			style:  STYLE_DEFAULT,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()

			// Original Merge
			optsOriginal := &MergeOptions{
				TextO: tt.origin,
				TextA: tt.ours,
				TextB: tt.theirs,
				Style: tt.style,
				A:     Histogram,
			}
			resultOriginal, conflictOriginal, errOriginal := Merge(ctx, optsOriginal)
			if errOriginal != nil {
				t.Fatalf("Merge() error = %v", errOriginal)
			}

			// MergeParallel
			optsNew := &MergeOptions{
				TextO: tt.origin,
				TextA: tt.ours,
				TextB: tt.theirs,
				Style: tt.style,
				A:     Histogram,
			}
			resultNew, conflictNew, errNew := MergeParallel(ctx, optsNew)
			if errNew != nil {
				t.Fatalf("MergeParallel() error = %v", errNew)
			}

			// Compare conflict flags
			if conflictOriginal != conflictNew {
				t.Errorf("Conflict mismatch: Merge=%v, MergeParallel=%v", conflictOriginal, conflictNew)
			}

			// Compare results
			if resultOriginal != resultNew {
				t.Errorf("Results differ:\nOriginal:\n%s\n\nMergeParallel:\n%s", resultOriginal, resultNew)
			}
		})
	}
}

