// TestMergeParallelLabels tests label formatting
func TestMergeParallelLabels(t *testing.T) {
	tests := []struct {
		name      string
		labelO    string
		labelA    string
		labelB    string
		wantLabel string
	}{
		{
			name:      "default_labels",
			labelO:    "o.txt",
			labelA:    "a.txt",
			labelB:    "b.txt",
			wantLabel: " a.txt", // ValidateOptions adds space
		},
		{
			name:      "empty_labels",
			labelO:    "",
			labelA:    "",
			labelB:    "",
			wantLabel: "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()
			opts := &MergeOptions{
				TextO:  "line1\nline2\n",
				TextA:  "line1a\nline2\n",
				TextB:  "line1b\nline2\n",
				LabelO: tt.labelO,
				LabelA: tt.labelA,
				LabelB: tt.labelB,
				Style:  STYLE_DEFAULT,
				A:      Histogram,
			}

			result, _, err := MergeParallel(ctx, opts)
			if err != nil {
				t.Fatalf("MergeParallel() error = %v", err)
			}

			if tt.labelA != "" {
				if !strings.Contains(result, tt.wantLabel) {
					t.Errorf("MergeParallel() result should contain label %q, got:\n%s", tt.wantLabel, result)
				}
			}
		})
	}
}

