// TestMergeParallelContext tests context cancellation
func TestMergeParallelContext(t *testing.T) {
	ctx, cancel := context.WithCancel(t.Context())
	cancel() // Cancel immediately

	opts := &MergeOptions{
		TextO: "line1\nline2\n",
		TextA: "line1a\nline2\n",
		TextB: "line1b\nline2\n",
		Style: STYLE_DEFAULT,
		A:     Histogram,
	}

	_, _, err := MergeParallel(ctx, opts)
	if err == nil {
		t.Error("MergeParallel() should return error when context is canceled")
	}
}

