// TestMergeParallelAlgorithms tests different diff algorithms
func TestMergeParallelAlgorithms(t *testing.T) {
	algorithms := []Algorithm{
		Histogram,
		Myers,
		ONP,
		Patience,
		Minimal,
	}

	for _, algo := range algorithms {
		t.Run(algo.String(), func(t *testing.T) {
			ctx := context.Background()
			opts := &MergeOptions{
				TextO: "line1\nline2\nline3\n",
				TextA: "line1a\nline2\nline3\n",
				TextB: "line1b\nline2\nline3\n",
				Style: STYLE_DEFAULT,
				A:     algo,
			}

			result, hasConflict, err := MergeParallel(ctx, opts)
			if err != nil {
				t.Fatalf("MergeParallel() with algorithm %s error = %v", algo, err)
			}

			if !hasConflict {
				t.Errorf("MergeParallel() with algorithm %s should detect conflict", algo)
			}

			if !strings.Contains(result, "<<<<<<<") {
				t.Errorf("MergeParallel() result should contain conflict markers")
			}
		})
	}
}

