// TestMergeParallelComplexConflicts tests complex conflict scenarios
func TestMergeParallelComplexConflicts(t *testing.T) {
	tests := []struct {
		name         string
		origin       string
		ours         string
		theirs       string
		wantConflict bool
	}{
		{
			name:         "both_delete_same",
			origin:       "line1\nline2\nline3\n",
			ours:         "line1\nline3\n",
			theirs:       "line1\nline3\n",
			wantConflict: false, // Same delete, no conflict
		},
		{
			name:         "both_delete_different",
			origin:       "line1\nline2\nline3\n",
			ours:         "line1\nline3\n",
			theirs:       "line1\nline2\n",
			wantConflict: false, // Adjacent deletions (line2 vs line3) don't overlap
		},
		{
			name:         "both_insert_same_place",
			origin:       "line1\nline3\n",
			ours:         "line1\nline2\nline3\n",
			theirs:       "line1\nline2a\nline3\n",
			wantConflict: true, // Different insert at same place
		},
		{
			name:         "replace_same_content",
			origin:       "line1\nline2\nline3\n",
			ours:         "line1\nline2a\nline3\n",
			theirs:       "line1\nline2a\nline3\n",
			wantConflict: false, // Same replacement, no conflict
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()
			opts := &MergeOptions{
				TextO: tt.origin,
				TextA: tt.ours,
				TextB: tt.theirs,
				Style: STYLE_DEFAULT,
				A:     Histogram,
			}

			_, hasConflict, err := MergeParallel(ctx, opts)
			if err != nil {
				t.Fatalf("MergeParallel() error = %v", err)
			}

			if hasConflict != tt.wantConflict {
				t.Errorf("MergeParallel() hasConflict = %v, want %v", hasConflict, tt.wantConflict)
			}
		})
	}
}

